import Storage from "./src/utils/storage.js";
import Marker from "./src/utils/marker.js";
import apiModel from "./src/model/apiModel.js";


export default class State {
    constructor() {
        this.devMode = true;
        this.storage = new Storage();
        this.marker = new Marker(this);

        this.user = 1;
        this.role = 'collaborator';
        this.project = 1;

        this.api = new apiModel();

        this.permissions = {
            "viewer":{ "read": true, "write": false, "delete": false },
            "collaborator":{ "read": true, "write": true, "delete": true },
            "owner":{ "read": true, "write": true, "delete": true }
        };

        this.teams = [
            {
                "label": "Developers",
                "value": "devloper",
                "children": [
                    { "value": "1", "label": "Pratik", "imageUrl": "https://i.pravatar.cc/30?img=1" },
                    { "value": "2", "label": "Vikram", "imageUrl": "https://i.pravatar.cc/30?img=2" }
                ]
            },
            {
                "label": "Sales",
                "value": "sales",
                "children": [
                    { "value": "3", "label": "kamlesh", "imageUrl": "https://i.pravatar.cc/30?img=3" },
                    { "value": "4", "label": "Isha", "imageUrl": "https://i.pravatar.cc/30?img=36" },
                    { "value": "5", "label": "Nilesh", "imageUrl": "https://i.pravatar.cc/30?img=5" }
                ]
            }
        ];

        this.status = [
            { "label": "Open", "value": "open" },
            { "label": "In Progress", "value": "in-progress" },
            { "label": "Resolved", "value": "resolved"},
            { "label": "Closed", "value": "closed"}
        ];

        this.priority = [
            { "label": "Low", "value": "low", "imageUrl": "https://placehold.co/30x30/blue/blue" },
            { "label": "Medium", "value": "medium", "imageUrl": "https://placehold.co/30x30/orange/orange" },
            { "label": "High", "value": "high", "imageUrl": "https://placehold.co/30x30/red/red" }
        ];


        this.explorer = true;

        this.EnabledTypes = ['inline'];
        this.bug = null;
        this.bugType = 'inline'; // inline , capture
        this.appStage = 'init';
        this.bugs = this.storage.getBugs() || [];
        this.overlay = { x: 0, y: 0, width: 0, height: 0, scrollX: 0, scrollY: 0, vh: 0, vw: 0 }

        this.loadBugs();
        console.log(this);
    }

    getState(option) {
        return this[option];
    }

    setState(option, value) {
        if (this.hasOwnProperty(option)) {
            this[option] = value;
            console.log(`State updated: ${option} = ${value}`);
        } else {
            console.warn(`Cannot set undefined property: ${option}`);
        }
    }

    // Add a method to add new bugs
    addBug(bug) {
        this.bugs.push(bug);
        this.storage.addNewBug(bug);
        return bug;
    }

    // update bug
    updateBug(id, data) {
        const bug = this.bugs.find(bug => bug.id === id);
        if (bug) {
            Object.assign(bug, data);
            this.storage.setItem('bugs', this.bugs);
        }
    }

    // Load bugs from storage and create markers
    async loadBugs() {
        if(this.devMode){
            this.bugs = this.storage.getBugs() || [];
            this.marker.loadMarker(this.bugs);
            return;
        }
        const bugs = await this.api.getAllBugs().then(data => {
            this.storage.setItem('bugs', data);
            this.bugs = data || [];
            console.log("bugs",this.bugs);
            this.marker.loadMarker(this.bugs);
            return data;
        });
        
        
    }

    // Get all bugs
    getBugs() {
        return this.bugs;
    }

    // Get a specific bug by ID
    getBugById(id) {
        return this.bugs.find(bug => bug.id === id);
    }
}

