export default class apiModel  {
    constructor() {
        //this.api_endpoint = "https://bugvault.2cube.studio/api/v1/";
        this.api_endpoint = "http://192.168.0.159:3031/api/v1/";

        this.slug = {
            ALL_BUGS: "task/id?id=",
            GET_PROJECT_BY_DOMAIN: "project?domain=",
            
        }
    }

    async getProject() {
        await fetch(`${this.api_endpoint}${this.slug.GET_PROJECT_BY_DOMAIN}${window.location.hostname}`)
        .then(response => {
            if (!response.ok) {
                throw new Error('Network response was not ok');
            }
            if(response.status === 404) {
                throw new Error('Project not found');
            }

            if(response.status === 200) {
                const data = response.json();
                if (data.total > 0) {
                    return data.properties[0];
                }else{
                    throw new Error('Project not found');
                }
            }
            
        })
        .catch(error => {
            console.error('Error:', error);
        });
        
    }

    async getAllBugs() {
        const response = await fetch(`${this.api_endpoint}${this.slug.ALL_BUGS}1`);
        const data = await response.json();
        return data;
    }
};