import { formatDate } from "../utils/date-formatter.js";
import Dragable from "../utils/dragable.js";
import DropdownSelect from "../utils/dropdown.js";

export default class ExplorerController {
  constructor(state) {
    this.state = state.state;
    this.explorerContainer = null;
    this.isOpen = false;

    
  }

  init() {
    // Create explorer button in the widget
    this.createExplorerButton();
    
    // Create explorer panel (initially hidden)
    this.createExplorerPanel();
    
    // Load bugs into the explorer
    // this.loadBugs();
    
    // Add event listeners
    this.addEventListeners();

    this.toggleExplorer();
  }
  
  createExplorerButton() {
    const widgetInner = document.getElementById('widgetOptionPickerInner');
    if (!widgetInner) return;
    
    const explorerBtn = document.createElement('div');
    explorerBtn.id = 'explorer-btn';
    explorerBtn.className = 'bug-widget-btn';
    explorerBtn.innerHTML = `
    <svg data-testid="geist-icon" height="16" stroke-linejoin="round" viewBox="0 0 16 16" width="16" style="color: currentcolor;"><path fill-rule="evenodd" clip-rule="evenodd" d="M6 3.5H10C12.4853 3.5 14.5 5.51472 14.5 8C14.5 10.4853 12.4853 12.5 10 12.5H6C3.51472 12.5 1.5 10.4853 1.5 8C1.5 5.51472 3.51472 3.5 6 3.5ZM0 8C0 4.68629 2.68629 2 6 2H10C13.3137 2 16 4.68629 16 8C16 11.3137 13.3137 14 10 14H6C2.68629 14 0 11.3137 0 8ZM7.5 8C7.5 8.82843 6.82843 9.5 6 9.5C5.17157 9.5 4.5 8.82843 4.5 8C4.5 7.17157 5.17157 6.5 6 6.5C6.82843 6.5 7.5 7.17157 7.5 8ZM9 8C9 9.65685 7.65685 11 6 11C4.34315 11 3 9.65685 3 8C3 6.34315 4.34315 5 6 5C7.65685 5 9 6.34315 9 8Z" fill="currentColor"></path></svg>
    `;
    widgetInner.appendChild(explorerBtn);
  }
  
  createExplorerPanel() {
    // Use the HTML template to create the explorer panel
    const template = document.createElement('template');
    template.innerHTML = `
      <div class="FlagBugMarker-explorer-panel FlagBugIO--border FlagBugIO--shadow">
        <div class="FlagBugIO--title-gd  FlagBugIO-flex FlagBugIO-justify-space-between">
          <div class="FlagBugIO-size--large FlagBugIO-weight--700">Bug Explorer</div>
          <div class="FlagBugMarker-explorer-close FlagBugIO-size--large FlagBugIO-weight--700">×</div>
        </div>
        <div class="FlagBugMarker-explorer-content">
          <div class="FlagBugMarker-explorer-filters-container FlagBugIO--filterInput
            FlagBugIO-row FlagBugIO-row-2 
          ">
            <div class="FlagBugIO-full">
              <div class="FlagBugIO-label">Priority</div>
              <div class="FlagBugMarker-explorer-filters filters-priority"></div>
            </div>
            <div class="FlagBugIO-full">
              <div class="FlagBugIO-label">Status</div>
              <div class="FlagBugMarker-explorer-filters filters-status"></div>
            </div>
          </div>
          <div class="FlagBugMarker-explorer-list FlagBugIO-flex FlagBugIO-flex-column FlagBugIO-flex-gap" id="FlagBugMarker-explorer-list">
          </div>
        </div>
      </div>
    `;
    
    // Get the explorer container from the template
    this.explorerContainer = template.content.firstElementChild.cloneNode(true);
    this.explorerContainer.id = 'FlagBugMarker-explorer-panel';
    
    // Make the filters priority
    new DropdownSelect({
      element: this.explorerContainer.querySelector('.filters-priority'),
      data: this.state.priority,
      type: "multi",
      styleType: "avatar",
      placeholder: "Filter by priority",
      closeOnSelect: true,
      searchable: false
    });

    // Make the filters status
    new DropdownSelect({
      element: this.explorerContainer.querySelector('.filters-status'),
      data: this.state.status,
      type: "multi",
      styleType: "avatar",
      placeholder: "Filter by status",
      closeOnSelect: true,
      searchable: false
    });

    // Make the panel draggable
    new Dragable(this.explorerContainer);
  }
  
  loadBugs() {
    if (!this.explorerContainer) return;
    
    const bugList = this.explorerContainer.querySelector('#FlagBugMarker-explorer-list');
    if (!bugList) return;
    
    // Clear existing bugs
    bugList.innerHTML = '';
    
    // Get bugs from state
    const bugs = this.state.getBugs();
    
    if (bugs.length === 0) {
      bugList.innerHTML = '<div class="FlagBugMarker-explorer-empty">No bugs found</div>';
      return;
    }
    
    // Create bug items using the template
    bugs.forEach(bug => {
      const template = document.createElement('template');

      // bug.description want to check if more then 100 words then trim and add ...
      if (bug.description.length > 90) {
        bug.description = bug.description.substring(0, 90) + '...';
      }

      template.innerHTML = `
        <div class="FlagBugMarker-explorer-item FlagBugIO-full FlagBugIO-status-${bug.status || 'open'}" data-bug-id="${bug.id}">
          <div class="FlagBugIO-flex FlagBugIO-justify-space-between">
            <div class="FlagBugIO-weight--700 FlagBugIO-size--medium">${bug.title}</div>
            <div class="FlagBugIO-badge FlagBugIO-bug-priority">${bug.priority || 'low'}</div>
          </div>
          
          <div class="FlagBugIO-weight--400 FlagBugIO-size--normal FlagBugIO-pt--small
            FlagBugIO-ellipsis
          ">${bug.description}</div>
          <div class="FlagBugIO-weight--700 FlagBugIO-pt--medium FlagBugIO-flex FlagBugIO-flex-gap
          FlagBugIO-size--small
          ">
          
          ${formatDate(bug.timestamp, false)}</div>
          
        </div>
      `;
      
      //<div class="FlagBugIO-bug-status">${bug.status || 'open'}</div>

      const bugItem = template.content.firstElementChild.cloneNode(true);
      
      // Add status and priority classes
      const statusEl = bugItem.querySelector('.FlagBugIO-bug-status');
      if (statusEl) {
        statusEl.classList.add(`FlagBugMarker-status-${bug.status || 'open'}`);
      }
      
      const priorityEl = bugItem.querySelector('.FlagBugIO-bug-priority');
      if (priorityEl) {
        priorityEl.classList.add(`FlagBugIO-badge--${bug.priority || 'low'}`);
      }
      
      bugList.appendChild(bugItem);
    });
  }
  
  
  
  getAssigneeName(assigneeId) {
    if (!assigneeId) return 'Unassigned';
    
    // Search through teams to find the assignee
    let assigneeName = 'Unknown';
    
    this.state.teams.forEach(team => {
      if (team.children) {
        team.children.forEach(member => {
          if (member.value === assigneeId) {
            assigneeName = member.label;
          }
        });
      }
    });
    
    return assigneeName;
  }
  
  toggleExplorer() {
    this.isOpen = !this.isOpen;
    
    if (this.isOpen) {
      // Refresh bug list before showing
      this.loadBugs();
      // Add the explorer panel to the DOM
      document.body.appendChild(this.explorerContainer);
    } else {
      // Remove the explorer panel from the DOM
      if (this.explorerContainer.parentNode) {
        this.explorerContainer.parentNode.removeChild(this.explorerContainer);
      }
    }
  }
  
  addEventListeners() {
    // Toggle explorer when clicking the explorer button
    const explorerBtn = document.getElementById('explorer-btn');
    if (explorerBtn) {
      explorerBtn.addEventListener('click', () => {
        this.toggleExplorer();
      });
    }
    
    // Close explorer when clicking the close button
    const closeBtn = this.explorerContainer.querySelector('.FlagBugMarker-explorer-close');
    if (closeBtn) {
      closeBtn.addEventListener('click', () => {
        this.toggleExplorer();
      });
    }
    
    // Handle bug item clicks
    const bugList = this.explorerContainer.querySelector('#FlagBugMarker-explorer-list');
    if (bugList) {
      bugList.addEventListener('click', (e) => {
        const bugItem = e.target.closest('.FlagBugMarker-explorer-item');
        if (bugItem) {
          const bugId = parseInt(bugItem.dataset.bugId);
          if (bugId) {
            // If clicking the same bug that's already open
            if (this.currentOpenBugId === bugId) {
              // Remove active class from the clicked item
              bugItem.classList.remove('FlagBugMarker--item-active');
              
              // Remove active class from the marker
              const marker = document.getElementById(`FlagBugMarker-${bugId}`);
              if (marker) marker.classList.remove('FlagBugMarker--item-active');
              
              // Reset current open bug ID
              this.currentOpenBugId = null;
            } else {
              // Remove active class from all items
              document.querySelectorAll('.FlagBugMarker-explorer-item').forEach(item => {
                item.classList.remove('FlagBugMarker--item-active');
              });
              
              // Remove active class from previous marker if exists
              if (this.currentOpenBugId) {
                const prevMarker = document.getElementById(`FlagBugMarker-${this.currentOpenBugId}`);
                if (prevMarker) prevMarker.classList.remove('FlagBugMarker--item-active');
              }
              
              // Add active class to the clicked item
              bugItem.classList.add('FlagBugMarker--item-active');
              
              // Add active class to the corresponding marker
              const marker = document.getElementById(`FlagBugMarker-${bugId}`);
              if (marker) marker.classList.add('FlagBugMarker--item-active');
              
              // Update current open bug ID
              this.currentOpenBugId = bugId;
            }
            
            // Trigger marker click event to view the bug
            const event = new CustomEvent('markerClicked', { 
              detail: { id: bugId } 
            });
            document.dispatchEvent(event);
          }
        }
      });
    }
    
    // Listen for bug updates to refresh the list
    document.addEventListener('bugUpdated', () => {
      if (this.isOpen) {
        this.loadBugs();
      }
    });
  }
}
