export default class DropdownSelect {
    constructor({ element, data, type = "single", placeholder = "Select", preselected = [],styleType = "default",closeOnSelect = true , permissions = 'create', searchable = true }) {
        this.element = element;
        // Normalize data format - convert flat array to grouped format if needed
        this.data = this.normalizeData(data);
        
        this.type = type;
        this.permissions = permissions;
        this.styleType = styleType;
        this.placeholder = placeholder;

        this.searchable = searchable;

        this.selected = new Set(
            preselected.flatMap(item => {
                // Check if the item contains commas
                if (typeof item === 'string' && item.includes(',')) {
                    // Split by comma and trim whitespace
                    return item.split(',').map(val => val.trim());
                }
                return item;
            })
        );
        this.highlightedIndex = 0;
        this.allOptionEls = [];
        this.eventListeners = {}; 
        this.closeOnSelect = closeOnSelect;


        this.prefix = "FlagBugIO--";
        this.staticClass = {
            container: `${this.prefix}dropdown-container`,
            selected: `${this.prefix}dropdown-selected`,
            menu: `${this.prefix}dropdown-menu`,
            search: `${this.prefix}dropdown-search`,
            group: `${this.prefix}dropdown-group`,
            option: `${this.prefix}dropdown-option`,
            selectedList: `${this.prefix}dropdown-selected-list`,
        }
        this.render();
        

    }
    static currentOpenInstance = null;
    static globalClickListener = null;

    render() {
        this.element.classList.add(this.staticClass.container);

        // Create the hidden input field
        this.selectedValue = document.createElement("input");
        this.selectedValue.type = "hidden";
        
        // Add a name attribute to make it work with forms
        this.selectedValue.name = `dropdown-${Date.now()}`;
        
        // Initialize the value based on preselected items
        this.updateSelectedValue();
        
        this.element.appendChild(this.selectedValue);

        this.selectedDiv = document.createElement("div");
        this.selectedDiv.className = this.staticClass.selected;
        
        this.selectedDiv.classList.add("FlagBugIO--control");

        this.selectedText = document.createElement("div");
        this.selectedDiv.appendChild(this.selectedText);

        
        if (this.permissions === 'create' || this.permissions === 'edit' ) {
            this.selectedDiv.onclick = (e) => {
                // Open menu ONLY if the user clicks directly on the selected box
                const isSelfClick = e.target === this.selectedDiv || e.target === this.selectedText;
                const isInsideTagList = e.target.closest(".dropdown-selected-list");
                if (isSelfClick && !isInsideTagList) {
                this.toggleMenu(e);
                }
            };
        }

        this.element.appendChild(this.selectedDiv);
        
        // Update selected text initially
        this.updateSelectedText();

        

        this.handleClickOutside = this.handleClickOutside.bind(this);

        document.addEventListener("keydown", (e) => this.handleKeydown(e));
    }

    handleClickOutside(e) {
        // Use setTimeout to wait until other clicks settle
        setTimeout(() => {
          if (
            this.menu &&
            !this.menu.contains(e.target) &&
            !this.selectedDiv.contains(e.target)
          ) {
            this.closeMenu();
          }
        }, 100);
      }

      toggleMenu(e) {
        if (!this.menu) {
            if (DropdownSelect.currentOpenInstance) {
                DropdownSelect.currentOpenInstance.closeMenu();
            }
    
            this.createMenu();
    
            setTimeout(() => {
                this.menu.classList.add("fade-in");
            }, 100);
    
            DropdownSelect.currentOpenInstance = this;
    
            if (!DropdownSelect.globalClickListener) {
                DropdownSelect.globalClickListener = (e) => {
                    const instance = DropdownSelect.currentOpenInstance;
                    if (
                        instance &&
                        instance.menu &&
                        !instance.element.contains(e.target)
                    ) {
                        instance.closeMenu();
                    }
                };
            
                document.addEventListener("click", DropdownSelect.globalClickListener);
            }

        } else {
            this.closeMenu();
        }
    }

    closeMenu() {
        if (this.menu) {
            this.menu.classList.remove("fade-in");
            setTimeout(() => {
                if (this.menu) {
                    this.menu.remove();
                    this.menu = null;
                }
            }, 300);
    
            if (DropdownSelect.currentOpenInstance === this) {
                DropdownSelect.currentOpenInstance = null;
            }
        }
    }

    createMenu() {
        this.menu = document.createElement("div");
        this.menu.className = `fade-in-el ${this.staticClass.menu}`;
        
        if(this.searchable){
            const searchInput = document.createElement("input");
            searchInput.className = this.staticClass.search;
            searchInput.classList.add("FlagBugIO--control");
            searchInput.placeholder = "Search...";
            
            // Add id and name attributes to fix the autofill warning
            const uniqueId = `dropdown-search-${Date.now()}`;
            searchInput.id = uniqueId;
            searchInput.name = uniqueId;
            searchInput.autocomplete = "off"; // Prevent autofill attempts
            
            searchInput.addEventListener("input", (e) => {
                this.filterOptions(e.target.value.toLowerCase());
            });
            
            const searchInputWrapper = document.createElement("div");
            searchInputWrapper.className = "FlagBugIO--searchInput";
            searchInputWrapper.appendChild(searchInput);
            this.menu.appendChild(searchInputWrapper);
        }

        this.optionContainer = document.createElement("div");
        this.optionContainer.className = "FlagBugIO--optionContainer";
        this.menu.appendChild(this.optionContainer);

        this.element.appendChild(this.menu);
        
        this.buildOptions(this.data);
    }

    buildOptions(data) {
        this.optionContainer.innerHTML = "";
        this.allOptionEls = [];
      
        // ===== SELECT ALL (Only in multi-select) =====
        if (this.type === "multi") {
          const selectAllContainer = document.createElement("div");
          selectAllContainer.className = this.staticClass.group;
          
      
          const selectAllCheckbox = document.createElement("input");
          selectAllCheckbox.type = "checkbox";
      
          const allValues = data.flatMap(g => g.children.map(c => c.value));
          const allSelected = allValues.every(val => this.selected.has(val));
          const someSelected = allValues.some(val => this.selected.has(val));
      
          selectAllCheckbox.checked = allSelected;
          selectAllCheckbox.indeterminate = !allSelected && someSelected;
      
          selectAllCheckbox.onclick = (e) => {
            e.stopPropagation();
            if (allSelected) {
              allValues.forEach(val => this.selected.delete(val));
            } else {
              allValues.forEach(val => this.selected.add(val));
            }
            this.buildOptions(this.data);
          };
        }
      
        // ===== GROUPS =====
        data.forEach((group) => {
            const groupEl = document.createElement("div");
            groupEl.className = this.staticClass.group;
            groupEl.classList.add("FlagBugIO--checkbox");
          
            const childValues = group.children.map((c) => c.value);
            const allSelected = childValues.every((val) => this.selected.has(val));
            const someSelected = childValues.some((val) => this.selected.has(val));
          
            // Only show group header if we have multiple groups or it's not the default "Options" group
            const showGroupHeader = data.length > 1 || group.label !== "Options";
            
            if (showGroupHeader) {
                // Checkbox only for multi-select
                if (this.type === "multi") {
                  const groupCheckbox = document.createElement("input");
                  groupCheckbox.type = "checkbox";
                  groupCheckbox.checked = allSelected;
                  groupCheckbox.indeterminate = !allSelected && someSelected;
              
                  groupCheckbox.onclick = (e) => {
                    e.stopPropagation();
                    this.toggleGroup(group);
                  };
              
                  groupEl.appendChild(groupCheckbox);
                }
              
                const label = document.createElement("span");
                label.innerText = group.label;
                
                groupEl.appendChild(label);
              
                if (allSelected) {
                  groupEl.classList.add("selected");
                }
              
                // Make whole group row clickable
                groupEl.onclick = (e) => {
                  e.stopPropagation();
                  this.toggleGroup(group);
                };
              
                this.optionContainer.appendChild(groupEl);
            }
          
            // Render each child option
            group.children.forEach((option) => {
              const optionEl = document.createElement("div");
              optionEl.className = this.staticClass.option;

              if (this.type === "multi") {
                optionEl.classList.add("FlagBugIO--checkbox");
              }
              
              
              optionEl.tabIndex = 0;
          
              if (this.selected.has(option.value)) {
                optionEl.classList.add("selected");
              }
          
              if (this.type === "multi") {
                const checkbox = document.createElement("input");
                checkbox.type = "checkbox";
                checkbox.checked = this.selected.has(option.value);
                checkbox.onclick = (e) => {
                  e.stopPropagation();
                  this.toggleOption(option);
                };
                optionEl.appendChild(checkbox);
              }
          
              const label = document.createElement("span");
          
              if (this.styleType === "avatar" && option.imageUrl) {
                const img = document.createElement("img");
                img.src = option.imageUrl;
                img.alt = option.label;
                img.style.width = "20px";
                img.style.height = "20px";
                img.style.borderRadius = "50%";
                img.style.marginRight = "8px";
                label.appendChild(img);
              }
          
              label.append(option.label);
              optionEl.appendChild(label);
          
              optionEl.onclick = (e) => {
                e.stopPropagation();
                this.toggleOption(option);
              };
          
              this.optionContainer.appendChild(optionEl);
              this.allOptionEls.push(optionEl);
            });
        });
      
        this.updateSelectedText();
    }

    toggleOption(option) {
        if (this.type === "single") this.selected.clear();

        if (this.selected.has(option.value)) {
            this.selected.delete(option.value);
        } else {
            this.selected.add(option.value);
        }

        this.buildOptions(this.data);
        this.updateSelectedValue(); 
        if (this.closeOnSelect && this.type === "single") {
            this.closeMenu();
        }
    }

    toggleGroup(group) {
        // For single selection, just select the first child
        if (this.type === "single") {
            this.selected.clear();
            if (group.children.length > 0) {
                this.selected.add(group.children[0].value);
            }
        } else {
            // For multi-selection, toggle all children
            const allSelected = group.children.every((opt) =>
                this.selected.has(opt.value)
            );
            group.children.forEach((opt) => {
                if (allSelected) this.selected.delete(opt.value);
                else this.selected.add(opt.value);
            });
        }

        this.buildOptions(this.data);
        this.updateSelectedValue(); // Update the hidden input value
    }

    filterOptions(query) {
        this.optionContainer.querySelectorAll(`.${this.staticClass.option}`).forEach((el) => {
            const label = el.innerText.toLowerCase();
            el.style.display = label.includes(query) ? "flex" : "none";
        });
    }

    updateSelectedText() {
        const selectedItems = [];
        const selectedValues = this.selected;
        const groupStates = [];

        this.selectedText.innerHTML = "";

        // Check if we're using a simple flat list (single group named "Options")
        const isSimpleList = this.data.length === 1 && this.data[0].label === "Options";

        this.data.forEach((group) => {
            const children = group.children;
            const childValues = children.map((c) => c.value);
            const allSelected = childValues.every((val) => selectedValues.has(val));
            const someSelected = childValues.some((val) => selectedValues.has(val));

            // For simple lists, don't show group labels
            if (allSelected && !isSimpleList) {
                selectedItems.push({
                    label: `${group.label} (${children.length})`,
                    value: group.value,
                    isGroup: true,
                    children
                });
            } else {
                children.forEach((child) => {
                    if (selectedValues.has(child.value)) {
                        selectedItems.push({
                            label: child.label,
                            value: child.value,
                            imageUrl: child.imageUrl
                        });
                    }
                });
            }

            groupStates.push({
                group,
                allSelected,
                someSelected
            });
        });

        if (selectedItems.length === 0) {
            this.selectedText.innerText = this.placeholder;
            return;
        }

        selectedItems.forEach(({ label, value, isGroup, children, imageUrl }) => {
            const tag = document.createElement("span");
            tag.className = this.staticClass.selectedList;
          
            if (this.styleType === "avatar" && imageUrl) {
                const img = document.createElement("img");
                img.src = imageUrl;
                img.alt = label;
                img.style.width = "18px";
                img.style.height = "18px";
                img.style.borderRadius = "50%";
                img.style.marginRight = "6px";
                tag.appendChild(img);
            } else if (isGroup && this.styleType === "avatar") {
                // For groups with avatar style, try to find an image
                const firstWithImage = children.find(c => c.imageUrl);
                if (firstWithImage?.imageUrl) {
                    const img = document.createElement("img");
                    img.src = firstWithImage.imageUrl;
                    img.alt = label;
                    img.style.width = "18px";
                    img.style.height = "18px";
                    img.style.borderRadius = "50%";
                    img.style.marginRight = "6px";
                    tag.appendChild(img);
                }
            }
          
            const labelEl = document.createElement("span");
            labelEl.innerText = label;
            tag.appendChild(labelEl);
            
            // Add a remove button
            if (this.permissions === 'create' || this.permissions === 'edit' ) {
            const removeBtn = document.createElement("span");
            removeBtn.innerText = " ×";
            removeBtn.style.marginLeft = "6px";
            removeBtn.style.cursor = "pointer";
            removeBtn.addEventListener("click", (e) => {
                e.stopPropagation();
                e.preventDefault();
                
                this.selected.delete(value);
                if (isGroup && children) {
                    children.forEach((c) => this.selected.delete(c.value));
                }
                
                // Update the selected text and hidden input value
                this.updateSelectedText();
                this.updateSelectedValue();
                
                if (this.menu) {
                    this.buildOptions(this.data);
                }
            });
            tag.appendChild(removeBtn);
            }

          
            if (isGroup) {
                tag.style.cursor = "pointer";
                tag.onclick = (e) => {
                    e.stopPropagation();
                    e.preventDefault();
                    
                    this.selected.delete(value);
                    children.forEach((c) => this.selected.add(c.value));
                    
                    // Update the selected text and hidden input value
                    this.updateSelectedText();
                    this.updateSelectedValue();
                    
                    if (this.menu) {
                        this.buildOptions(this.data);
                    }
                };
            }
          
            
            this.selectedText.appendChild(tag);
        });
    }

    flattenItems(data) {
        return data.reduce((acc, group) => {
            return acc.concat(group.children.map((child) => ({
                ...child
            })));
        }, []);
    }

    handleKeydown(e) {
        if (!this.menu) return;

        const visibleOptions = this.allOptionEls.filter(
            (el) => el.offsetParent !== null
        );
        if (visibleOptions.length === 0) return;

        if (e.key === "ArrowDown" || e.key === "Tab") {
            e.preventDefault();
            this.highlightedIndex =
                (this.highlightedIndex + 1) % visibleOptions.length;
            visibleOptions[this.highlightedIndex].focus();
        } else if (e.key === "ArrowUp") {
            e.preventDefault();
            this.highlightedIndex =
                (this.highlightedIndex - 1 + visibleOptions.length) %
                visibleOptions.length;
            visibleOptions[this.highlightedIndex].focus();
        } else if (e.key === "Enter") {
            e.preventDefault();
            visibleOptions[this.highlightedIndex]?.click();
        } else if (e.key === "Escape") {
            this.closeMenu();
        }
    }

    getValue() {
        return Array.from(this.selected);
    }

    // Add methods for event handling
    addEventListener(eventName, callback) {
        if (!this.eventListeners[eventName]) {
            this.eventListeners[eventName] = [];
        }
        this.eventListeners[eventName].push(callback);
    }

    removeEventListener(eventName, callback) {
        if (this.eventListeners[eventName]) {
            this.eventListeners[eventName] = this.eventListeners[eventName]
                .filter(listener => listener !== callback);
        }
    }

    dispatchEvent(eventName, data) {
        if (this.eventListeners[eventName]) {
            const event = { type: eventName, data };
            this.eventListeners[eventName].forEach(callback => callback(event));
        }
    }

    updateSelectedValue() {
        if (this.type === "single") {
            const selectedValues = Array.from(this.selected);
            this.selectedValue.value = selectedValues.length > 0 ? selectedValues[0] : '';
        } else {
            // For multi-select, join all selected values with a comma
            this.selectedValue.value = Array.from(this.selected).join(',');
        }
        
        // Dispatch our custom getValue event
        this.dispatchEvent('change', Array.from(this.selected));
        
        
    }

    // Add this new method to normalize data format
    normalizeData(data) {
        // Check if data is already in the grouped format
        if (data.length > 0 && data[0].children) {
            return data;
        }
        
        // Convert flat array to grouped format
        return [{
            label: "Options",
            value: "options",
            children: data.map(item => ({
                value: item.value,
                label: item.label,
                imageUrl: item.imageUrl
            }))
        }];
    }
}
