import Storage from './storage.js';

export default class Dragable {
    constructor(element) {
        this.element = element;

        if (!this.element) {
            throw new Error('Element not found');
        }


        this.dragging = false;
        this.threshold = 10;
        this.startX = 0;
        this.startY = 0;

        this.makeWidgetDraggable(this.element);
    }


   makeWidgetDraggable(element) {
        const container = this.element;
        let isDragging = false;
        let offsetX, offsetY;
        
        // Try to load saved position from localStorage
        try {
            const storage = new Storage();
            const savedPosition = storage.getItem('widgetPosition') || { x: 0, y: 15 };
            
            const windowHeight = window.innerHeight;
            // Ensure the y position is at least 15px from top and bottom
            const adjustedY = Math.min(
                Math.max(15, savedPosition.y),
                windowHeight - 100 // Approximate widget height, adjust as needed
            );
            
            // Add alignment classes based on saved position
            if (savedPosition.x === 0) {
                container.classList.add('align-left');
                container.classList.remove('align-right');
            } else {
                container.classList.add('align-right');
                container.classList.remove('align-left');
            }
            
            // Apply saved position
            container.style.left = savedPosition.x === 0 ? '15px' : 'auto';
            container.style.right = savedPosition.x === 1 ? '15px' : 'auto';
            container.style.top = `${adjustedY}px`;
        } catch (e) {
            console.error('Error loading saved position:', e);
        }
        
        // Add draggable attribute and cursor style
        container.setAttribute('draggable', 'true');
        container.style.cursor = 'move';
        
        // Mouse down event to start dragging
        container.addEventListener('mousedown', function(e) {
            // Only handle left mouse button
            if (e.button !== 0) return;
            
            isDragging = true;
            
            // Add dragging class
            container.classList.add('dragging');
            
            // Disable transition during drag
            container.style.transition = 'none';
            
            // Calculate the offset from the mouse position to the container's top-left corner
            const rect = this.getBoundingClientRect();
            offsetX = e.clientX - rect.left;
            offsetY = e.clientY - rect.top;
            
            // Prevent text selection during drag
            e.preventDefault();
        });
        
        // Mouse move event to update position
        document.addEventListener('mousemove', (e) => {
            if (!isDragging) return;
            
            // Calculate new position
            const x = e.clientX - offsetX;
            const y = e.clientY - offsetY;
            
            // Apply new position
            container.style.left = `${x}px`;
            container.style.top = `${y}px`;
            container.style.right = 'auto'; // Remove any right positioning
            container.style.bottom = 'auto'; // Remove any bottom positioning
        });
        
        // Mouse up event to stop dragging
        document.addEventListener('mouseup', () => {
            if (!isDragging) return;
            
            isDragging = false;
            container.classList.remove('dragging');
            
            // Get the current position
            const rect = container.getBoundingClientRect();
            const y = Math.max(15, rect.top); // Ensure minimum 15px from top
            const windowHeight = window.innerHeight;
            
            // Ensure minimum 15px from bottom
            const adjustedY = Math.min(y, windowHeight - rect.height - 15);
            
            // Determine whether to snap to left or right
            const windowWidth = window.innerWidth;
            const centerX = windowWidth / 2;
            const isLeft = rect.left < centerX;
            
            // Calculate the final position
            if (isLeft) {
                // For left side, animate to left: 15px
                container.style.transition = 'all 0.2s ease';
                container.style.left = '15px'; // 15px from left edge
                container.style.right = 'auto';
                container.style.top = `${adjustedY}px`;
                container.classList.add('align-left');
                container.classList.remove('align-right');
            } else {
                // For right side, we need to calculate the right position
                const rightPosition = Math.max(15, windowWidth - (rect.left + rect.width));
                
                // First set the right position without animation
                container.style.transition = 'none';
                container.style.right = `${rightPosition}px`;
                container.style.left = 'auto';
                container.style.top = `${adjustedY}px`;
                
                // Force a reflow
                void container.offsetHeight;
                
                // Then animate to right: 15px
                container.style.transition = 'right 0.2s ease, top 0.2s ease';
                container.style.right = '15px'; // 15px from right edge
                container.classList.add('align-right');
                container.classList.remove('align-left');
            }
            
            // Save position to localStorage (0 for left, 1 for right)
            const xPosition = isLeft ? 0 : 1;
            try {
                const storage = new Storage();
                storage.setItem('widgetPosition', { x: xPosition, y: adjustedY });
                console.log("Widget position saved:", { x: xPosition, y: adjustedY });
            } catch (e) {
                console.error('Error saving position:', e);
            }
        });
        
        // Mouse leave event to stop dragging if cursor leaves the document
        document.addEventListener('mouseleave', () => {
            if (isDragging) {
                isDragging = false;
                container.classList.remove('dragging');
                container.style.transition = 'all 0.2s ease';
            }
        });
        
        console.log("Widget button made draggable");
    }
}
