import { CaptureModel } from "../model/CaptureModel.js";
import Overlay from "../utils/overlay.js";
import { CaptureView } from "../view/CaptureView.js";


export class CaptureController {
  constructor(state) {
    this.state = state.state;

    this.view = new CaptureView();
    this.model = new CaptureModel(this.state);

    this.overlay = new Overlay();
  }

  init() {
    this.view.renderButton();
    this.view.bindClick(() => {
      this.state.setState('bugType', 'capture');
      this.overlay.show();
      this.overlay.overlay.addEventListener('click', (e) => {
        const viewportInfo = this.overlay.getInfo(e);
        this.state.setState('overlay', viewportInfo);
        this.overlay.hide();
      });

      //this.model.saveCapture('Simulated Screenshot'); // Later, use real screenshot
    });
  }
}